+        _newAssignee = string.Empty;
+        _newPriority = "Medium";
+        _newDueDate = DateTime.Today.AddDays(7);
+        _formError = null;
+    }
+
+    private void CancelAdd()
+    {
+        _addingColumn = null;
+        _formError = null;
+    }
+
+    private async Task SaveNewTaskAsync()
+    {
+        if (string.IsNullOrWhiteSpace(_newTitle))
+        {
+            _formError = "Title is required.";
+            return;
+        }
+
+        try
+        {
+            _saving = true;
