+@page "/board"
+@using sv_52fba43a1f6a4859ad039e4c23828835
+@inject ITaskService TaskService
+@rendermode InteractiveServer
+
+<PageTitle>Kanban Board</PageTitle>
+
+<h1 class="mb-4">Project Board</h1>
+
+@if (_loading)
+{
+    <div class="d-flex justify-content-center my-5">
+        <div class="spinner-border" role="status">
+            <span class="visually-hidden">Loading...</span>
+        </div>
+    </div>
+}
+else if (_errorMessage is not null)
+{
+    <div class="alert alert-danger" role="alert">
+        <strong>Error:</strong> @_errorMessage
+        <button class="btn btn-sm btn-outline-danger ms-3" @onclick="LoadTasksAsync">Retry</button>
+    </div>
+}
+else
+{
+    @* ── Summary Stats Bar ── *@
+    <div class="row g-2 mb-3">
+        <div class="col">
+            <div class="card text-center">
+                <div class="card-body py-2">
+                    <div class="fw-bold">Total</div>
+                    <div class="fs-5">@_allTasks.Count</div>
+                </div>
+            </div>
+        </div>
+        @foreach (var col in Columns)
+        {
+            <div class="col">
+                <div class="card text-center">
+                    <div class="card-body py-2">
+                        <div class="fw-bold">@col</div>
+                        <div class="fs-5">@CountByStatus(col)</div>
+                    </div>
+                </div>
+            </div>
+        }
+        <div class="col">
+            <div class="card text-center border-danger">
+                <div class="card-body py-2">
+                    <div class="fw-bold text-danger">Overdue</div>
+                    <div class="fs-5 text-danger">@_allTasks.Count(t => t.DueDate < DateTime.Today)</div>
+                </div>
+            </div>
+        </div>
+    </div>
+
+    @* ── Search Bar ── *@
+    <div class="mb-3">
+        <input type="text" class="form-control" placeholder="Search tasks by title..."
+               @bind="_searchText" @bind:event="oninput" />
+    </div>
+
+    @* ── Kanban Columns ── *@
+    <div class="row g-3">
+        @for (int i = 0; i < Columns.Length; i++)
+        {
+            var colIndex = i;
+            var colName = Columns[colIndex];
+            var tasks = FilteredTasksByStatus(colName);
+
+            <div class="col-md-4">
+                <div class="card h-100">
+                    <div class="card-header d-flex justify-content-between align-items-center">
+                        <span class="fw-bold">@colName</span>
+                        <span class="badge bg-secondary">@tasks.Count</span>
+                    </div>
+                    <div class="card-body d-flex flex-column gap-2 p-2" style="min-height: 200px;">
+                        @foreach (var task in tasks)
+                        {
+                            <div class="card shadow-sm">
+                                <div class="card-body p-2">
+                                    <h6 class="card-title mb-1">@task.Title</h6>
+                                    <p class="card-text text-muted mb-1" style="font-size: .85rem;">
+                                        @task.Assignee
+                                    </p>
+                                    <div class="d-flex justify-content-between align-items-center mb-1">
+                                        <span class="badge @PriorityBadgeClass(task.Priority)">
+                                            @task.Priority
+                                        </span>
+                                        <small class="text-muted">@task.DueDate.ToString("MMM dd")</small>
+                                    </div>
+                                    <div class="d-flex justify-content-between mt-1">
+                                        @if (colIndex > 0)
+                                        {
+                                            <button class="btn btn-sm btn-outline-secondary"
+                                                    @onclick="() => MoveTaskAsync(task.Id, Columns[colIndex - 1])">
+                                                &larr; Move Left
+                                            </button>
+                                        }
+                                        else
+                                        {
+                                            <span></span>
+                                        }
+                                        @if (colIndex < Columns.Length - 1)
+                                        {
+                                            <button class="btn btn-sm btn-outline-secondary"
+                                                    @onclick="() => MoveTaskAsync(task.Id, Columns[colIndex + 1])">
+                                                Move Right &rarr;
+                                            </button>
+                                        }
+                                    </div>
+                                </div>
+                            </div>
+                        }
+
+                        @* ── Inline Add-Task Form ── *@
+                        @if (_addingColumn == colName)
+                        {
+                            <div class="card border-primary mt-auto">
+                                <div class="card-body p-2 d-flex flex-column gap-2">
+                                    <input type="text" class="form-control form-control-sm"
+                                           placeholder="Title" @bind="_newTitle" />
+                                    <input type="text" class="form-control form-control-sm"
+                                           placeholder="Assignee" @bind="_newAssignee" />
+                                    <select class="form-select form-select-sm" @bind="_newPriority">
+                                        <option value="High">High</option>
+                                        <option value="Medium">Medium</option>
+                                        <option value="Low">Low</option>
+                                    </select>
+                                    <input type="date" class="form-control form-control-sm" @bind="_newDueDate" />
+                                    <div class="d-flex gap-2">
+                                        <button class="btn btn-sm btn-primary flex-fill"
+                                                @onclick="SaveNewTaskAsync" disabled="@_saving">
+                                            Save
+                                        </button>
+                                        <button class="btn btn-sm btn-outline-secondary flex-fill"
+                                                @onclick="CancelAdd" disabled="@_saving">
+                                            Cancel
+                                        </button>
+                                    </div>
+                                    @if (_formError is not null)
+                                    {
+                                        <div class="text-danger small">@_formError</div>
+                                    }
+                                </div>
+                            </div>
+                        }
+                        else
+                        {
+                            <button class="btn btn-sm btn-outline-primary mt-auto"
+                                    @onclick="() => StartAdd(colName)">
+                                + Add Task
+                            </button>
+                        }
+                    </div>
+                </div>
+            </div>
+        }
+    </div>
+}
+
+@code {
+    private static readonly string[] Columns = { "To Do", "In Progress", "Done" };
+
+    private List<TaskItem> _allTasks = new();
+    private bool _loading = true;
+    private string? _errorMessage;
+    private string _searchText = string.Empty;
+
+    // Add-task form state
+    private string? _addingColumn;
+    private string _newTitle = string.Empty;
+    private string _newAssignee = string.Empty;
+    private string _newPriority = "Medium";
+    private DateTime _newDueDate = DateTime.Today.AddDays(7);
+    private bool _saving;
+    private string? _formError;
+
+    protected override async Task OnInitializedAsync()
+    {
+        await LoadTasksAsync();
+    }
+
+    private async Task LoadTasksAsync()
+    {
+        try
+        {
+            _loading = true;
+            _errorMessage = null;
+            _allTasks = await TaskService.GetAllTasksAsync();
+        }
+        catch (Exception ex)
+        {
+            _errorMessage = ex.Message;
+        }
+        finally
+        {
+            _loading = false;
+        }
+    }
+
+    private int CountByStatus(string status) =>
+        _allTasks.Count(t => t.Status == status);
+
+    private List<TaskItem> FilteredTasksByStatus(string status) =>
+        _allTasks
+            .Where(t => t.Status == status &&
+                        (string.IsNullOrWhiteSpace(_searchText) ||
+                         t.Title.Contains(_searchText, StringComparison.OrdinalIgnoreCase)))
+            .ToList();
+
+    private static string PriorityBadgeClass(string priority) => priority switch
+    {
+        "High" => "bg-danger",
+        "Medium" => "bg-warning text-dark",
+        "Low" => "bg-success",
+        _ => "bg-secondary"
+    };
+
+    private async Task MoveTaskAsync(int taskId, string newStatus)
+    {
+        try
+        {
+            await TaskService.UpdateTaskStatusAsync(taskId, newStatus);
+            var idx = _allTasks.FindIndex(t => t.Id == taskId);
+            if (idx >= 0)
+            {
+                var old = _allTasks[idx];
+                _allTasks[idx] = old with { Status = newStatus };
+            }
+        }
+        catch (Exception ex)
+        {
+            _errorMessage = ex.Message;
+        }
+    }
+
+    private void StartAdd(string column)
+    {
+        _addingColumn = column;
+        _newTitle = string.Empty;
+        _newAssignee = string.Empty;
+        _newPriority = "Medium";
+        _newDueDate = DateTime.Today.AddDays(7);
+        _formError = null;
+    }
+
+    private void CancelAdd()
+    {
+        _addingColumn = null;
+        _formError = null;
+    }
+
+    private async Task SaveNewTaskAsync()
+    {
+        if (string.IsNullOrWhiteSpace(_newTitle))
+        {
+            _formError = "Title is required.";
+            return;
+        }
+
+        try
+        {
+            _saving = true;
+            _formError = null;
+            var created = await TaskService.CreateTaskAsync(
+                _newTitle.Trim(), _newAssignee.Trim(), _newPriority, _newDueDate);
+            // The service creates tasks; place them in the current column
+            _allTasks.Add(created with { Status = _addingColumn! });
+            _addingColumn = null;
+        }
+        catch (Exception ex)
+        {
+            _formError = ex.Message;
+        }
+        finally
+        {
+            _saving = false;
+        }
+    }
+}
+

